import React, { useEffect, useRef, useState } from 'react';
import '../styles/GameCanvas.css';
import { AWS_ICON_CATEGORIES, SERVICE_MAPPINGS } from '../services/IconResolver';

// For debugging: Hard-code a known category that actually has icons
// (Update this to a real category name in your AWS_ICON_CATEGORIES / SERVICE_MAPPINGS)
const HARDCODED_CATEGORY = "/Analytics"; 

// If your code requires these constants:
const S3_BUCKET_URL = 'https://hackthon-backend-files-ep-2024.s3.amazonaws.com';
const ICONS_BASE_PATH = '/amazon-icons-set/Architecture-Service-Icons_06072024';
const S3_ROCKET_PATH = `${S3_BUCKET_URL}/games/rocket`;
const DEFAULT_ROCKET = `${S3_ROCKET_PATH}/rocket1.png`;
const FIREBALL_PATH = `${S3_BUCKET_URL}/games/bullet/fireball.png`;

export default function GameCanvas() {
  const canvasRef = useRef(null);
  const iconsRef = useRef([]);
  const bulletsRef = useRef([]);

  // We do a "minimal" approach: no modals, no user flow
  // We'll just force it to start
  const [gameStarted, setGameStarted] = useState(false);
  const [timeLeft, setTimeLeft] = useState(60);
  const [score, setScore] = useState(0);

  // Hard-code the rocket
  const rocketImage = useRef(new Image());
  useEffect(() => {
    rocketImage.current.src = DEFAULT_ROCKET;
  }, []);

  // Hard-code bullet
  const fireballImage = useRef(new Image());
  useEffect(() => {
    fireballImage.current.src = FIREBALL_PATH;
  }, []);

  // Gun info
  const gunRef = useRef({
    x: 400 - 25,
    y: 700,
    width: 100,
    height: 100,
  });

  // Particle references (if needed)
  const particlesRef = useRef([]);

  // Minimal instructions: just one category
  const instructions = [
    {
      text: "Shoot the Analytics icons!",
      category: HARDCODED_CATEGORY,
      displayName: "Analytics"
    }
  ];
  // We'll skip index stuff and just do index=0
  const currentInstructionIndex = 0;

  // Hard-coded "playerName" for debug
  const playerName = "DebugPlayer";

  // We define a minimal "load icons" function
  const loadIcons = () => {
    console.log("loadIcons called");
    iconsRef.current = [];

    const canvas = canvasRef.current;
    if (!canvas) return;
    const getRandomX = () => Math.floor(Math.random() * (canvas.width - 50));

    // Let's pick 4 correct icons
    const categoryIcons = Object.entries(SERVICE_MAPPINGS)
      .filter(([_, path]) => path.includes(HARDCODED_CATEGORY))
      .map(([name, path]) => ({
        path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
        name,
        category: HARDCODED_CATEGORY
      }));
    console.log("Category icons found:", categoryIcons.length);

    // We'll just pick 4 from that category
    let correctIcons = [];
    if (categoryIcons.length === 0) {
      console.warn("No icons found for HARDCODED_CATEGORY. Are you sure it exists?");
    } 
    else if (categoryIcons.length <= 4) {
      while (correctIcons.length < 4) {
        correctIcons.push(...categoryIcons.slice(0, 4 - correctIcons.length));
      }
    } else {
      correctIcons = [...categoryIcons].sort(() => 0.5 - Math.random()).slice(0, 4);
    }

    // We'll add 6 "wrong" icons from other categories
    const otherCategoryIcons = Object.entries(SERVICE_MAPPINGS)
      .filter(([_, path]) => !path.includes(HARDCODED_CATEGORY))
      .map(([name, path]) => ({
        path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
        name,
        category: "OTHER"
      }));
    let wrongIcons = [];
    if (otherCategoryIcons.length === 0) {
      console.warn("No icons found for 'other' categories. Possibly HARDCODED_CATEGORY is everywhere?");
    }
    else if (otherCategoryIcons.length <= 6) {
      while (wrongIcons.length < 6) {
        wrongIcons.push(...otherCategoryIcons.slice(0, 6 - wrongIcons.length));
      }
    } else {
      wrongIcons = [...otherCategoryIcons].sort(() => 0.5 - Math.random()).slice(0, 6);
    }

    // Combine them
    const finalIcons = [...correctIcons, ...wrongIcons];
    console.log("Final icons to place:", finalIcons.length);

    // Place them randomly at the top
    const positionsUsed = [];
    finalIcons.forEach(iconInfo => {
      const iconImg = new Image();
      iconImg.src = iconInfo.path;
      let x = getRandomX();
      while (positionsUsed.some(px => Math.abs(px - x) < 50)) {
        x = getRandomX();
      }
      positionsUsed.push(x);

      iconsRef.current.push({
        x,
        y: -50,
        type: iconInfo.category,   // "OTHER" or HARDCODED_CATEGORY
        name: iconInfo.name,
        image: iconImg,
        hit: false
      });
    });
  };

  // Minimal collision
  const checkCollisions = () => {
    const canvas = canvasRef.current;
    const currentCategory = HARDCODED_CATEGORY; // There's only 1 mission for debugging

    iconsRef.current.forEach((icon, iIndex) => {
      bulletsRef.current = bulletsRef.current.filter((bullet) => {
        const withinX = bullet.x > icon.x && bullet.x < icon.x + 50;
        const withinY = bullet.y > icon.y && bullet.y < icon.y + 50;
        if (withinX && withinY) {
          icon.hit = true;
          if (icon.type === currentCategory) {
            setScore(prev => prev + 5);
            console.log("Hit CORRECT icon:", icon.name);
          } else {
            setScore(prev => prev - 5);
            console.log("Hit WRONG icon:", icon.name);
          }
          iconsRef.current.splice(iIndex, 1);
          return false; 
        }
        return true;
      });
    });
  };

  // Main loop
  const gameLoop = () => {
    if (!gameStarted || !canvasRef.current) return;
    const ctx = canvasRef.current.getContext('2d');
    ctx.clearRect(0, 0, canvasRef.current.width, canvasRef.current.height);

    console.log("Game Loop Running"); // So we can see it in console

    // Draw rocket
    const { x: gunX, y: gunY, width, height } = gunRef.current;
    ctx.drawImage(rocketImage.current, gunX, gunY, width, height);

    // Draw icons
    iconsRef.current.forEach(icon => {
      if (!icon.hit) {
        ctx.drawImage(icon.image, icon.x, icon.y, 50, 50);
        icon.y += 1; // drop speed
      }
    });

    // Remove off screen icons
    iconsRef.current = iconsRef.current.filter(icon => icon.y < canvasRef.current.height);

    // Draw bullets
    bulletsRef.current.forEach(b => {
      ctx.drawImage(fireballImage.current, b.x, b.y, 20, 20);
      b.y -= 5;
    });
    bulletsRef.current = bulletsRef.current.filter(b => b.y > 0);

    // Collisions
    checkCollisions();

    requestAnimationFrame(gameLoop);
  };

  // Start automatically
  useEffect(() => {
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      canvas.width = 800;
      canvas.height = 600;
      setGameStarted(true);
      loadIcons();
      requestAnimationFrame(gameLoop);
    }
  }, []);

  // Minimal mouse events
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      let newX = e.clientX - rect.left - gunRef.current.width / 2;
      newX = Math.max(0, Math.min(newX, canvas.width - gunRef.current.width));
      gunRef.current.x = newX;
    };

    const handleCanvasClick = () => {
      if (gameStarted && timeLeft > 0) {
        bulletsRef.current.push({
          x: gunRef.current.x + gunRef.current.width / 2 - 10,
          y: gunRef.current.y - 20
        });
      }
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('click', handleCanvasClick);
    return () => {
      canvas.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('click', handleCanvasClick);
    };
  }, [gameStarted]);

  // Minimal timer
  useEffect(() => {
    if (gameStarted && timeLeft > 0) {
      const timer = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
      return () => clearInterval(timer);
    }
  }, [gameStarted, timeLeft]);

  return (
    <div style={{ display: 'flex' }}>
      <div>
        <canvas ref={canvasRef} style={{ border: '1px solid black' }} />
      </div>
      <div style={{ marginLeft: 20 }}>
        <h3>Minimal AWS Shooter (Debug Version)</h3>
        <p>Time Left: {timeLeft}</p>
        <p>Score: {score}</p>
        <p>Category: {HARDCODED_CATEGORY}</p>
        <p>Player: {playerName}</p>
      </div>
    </div>
  );
}
